noncompliant:
// Virtual comparison operators are problematic and error-prone
struct Base {
    virtual bool operator==(const Base& other) const; // Noncompliant
    virtual bool operator!=(const Base& other) const; // Noncompliant
    virtual bool operator<(const Base& other) const;  // Noncompliant
};

class Shape {
public:
    virtual bool operator==(const Shape& other) const { // Noncompliant
        return typeid(*this) == typeid(other);
    }
};

compliant:
// Use non-virtual comparison operators
struct Point {
    int x, y;

    bool operator==(const Point& other) const { // Compliant
        return x == other.x && y == other.y;
    }

    bool operator!=(const Point& other) const { // Compliant
        return !(*this == other);
    }
};

// For polymorphic comparison, use a separate virtual method
class Shape {
public:
    virtual bool equals(const Shape& other) const = 0; // Compliant
    virtual ~Shape() = default;
};

class Circle : public Shape {
    double radius;
public:
    bool equals(const Shape& other) const override {
        const Circle* circle = dynamic_cast<const Circle*>(&other);
        return circle && radius == circle->radius;
    }
};
